+// doctorTestServerPort returns the Dolt server port for doctor tests.
+func doctorTestServerPort() int {
+	if p := os.Getenv("BEADS_DOLT_PORT"); p != "" {
+		if port, _ := strconv.Atoi(p); port > 0 {
+			return port
+		}
+	}
+	return 3307 // default dolt sql-server port
+}
